/**
 * `requestAttestation` — transport-agnostic entry point for RPs.
 *
 * This is the v0.2 headline API. It walks a list of `Transport`s in
 * order, hands the first response that arrives to the SPEC §9.9
 * verifier, and returns a single discriminated-union result.
 *
 * Compared to the v0.1 `openVerifyPopup`:
 *   - The RP doesn't pre-commit to ONE wallet URL — they describe a
 *     menu of ways to reach a wallet (extension, popup, QR, deep link)
 *     and the SDK picks the first one that works.
 *   - The trust check moves from "validate iss against allowedIssuers
 *     after a popup-only flow" to "validate iss against allowedIssuers
 *     against whatever transport returned the attestation". Same rule,
 *     uniformly applied.
 */

import {
  buildRpVerifyRequest,
  verifyRpVerifyResponse,
  InMemoryNonceStore,
  ProtocolError,
  type RpVerifyRequest,
  type RpVerifyResponse,
  type RpVerifyErrorResponse,
  type RpScope,
  type IssuerPubkeyResolver,
  type NonceStore,
  type VerifyRpResponseResult,
} from "@workspace/numkeys-protocol";

import {
  dispatchPopup,
  dispatchExtension,
  dispatchRedirect,
  dispatchQr,
  type Transport,
  type TransportOutcome,
} from "./transports.js";

export interface TrustPolicy {
  /**
   * Issuer `iss` values your application accepts attestations from.
   * **Checked AFTER the wallet returns a response and BEFORE any
   * issuer-pubkey network fetch** (SSRF defense).
   */
  allowedIssuers: string[];
  /** Reject attestations older than this. Default 365 days. */
  maxAttestationAgeSec?: number;
  /** Tolerance for response.iat in the future. Default 60s. */
  clockSkewSec?: number;
}

export interface RequestAttestationParams {
  rpOrigin: string;
  rpName: string;
  scope: RpScope;
  /** REQUIRED if `scope === "phone"`. E.164 format. */
  candidatePhoneE164?: string;
  /** Request lifetime. Default 120s. Max 300s. */
  ttlSec?: number;
  /**
   * Transports tried in order. The dispatcher uses the first one that
   * yields a response. Transports that can't even start (popup blocked,
   * no extension installed) are skipped silently.
   *
   * Recommended order: extension → popup → qr (desktop), or
   * extension → deepLink → qr (mobile).
   */
  transports: Transport[];
  trustPolicy: TrustPolicy;
  getIssuerPubkey: IssuerPubkeyResolver;
  /** Defaults to a per-call InMemoryNonceStore. NOT safe in production. */
  nonceStore?: NonceStore;
  windowRef?: Window;
}

export type RequestAttestationResult =
  | {
      ok: true;
      transport: Transport["kind"];
      result: VerifyRpResponseResult;
      response: RpVerifyResponse;
    }
  | {
      ok: false;
      reason: "declined";
      transport: Transport["kind"];
      error: string;
    }
  | {
      ok: false;
      reason: "verification_failed";
      transport: Transport["kind"];
      error: string;
    }
  | {
      ok: false;
      reason: "timeout";
      transport: Transport["kind"];
    }
  | {
      ok: false;
      reason: "navigated";
      transport: "redirect";
      /**
       * The request that was sent, so the caller can persist it for
       * `consumeRedirectFragment` on the return page. (The redirect
       * transport may also receive a `persistRequest` callback and do
       * this for you.)
       */
      request: RpVerifyRequest;
    }
  | {
      ok: false;
      reason: "no_transport_available";
      tried: Array<{ transport: Transport["kind"]; reason: string }>;
    };

/**
 * Build a request and dispatch it. **Never throws** — every outcome,
 * including invalid configuration, is encoded in the result union.
 */
export async function requestAttestation(
  params: RequestAttestationParams,
): Promise<RequestAttestationResult> {
  if (params.transports.length === 0) {
    return { ok: false, reason: "no_transport_available", tried: [] };
  }

  // Validate redirect transport's returnUrl is on rpOrigin (defense
  // against misconfiguration sending fragment data to a third party).
  const redirect = params.transports.find((t): t is Extract<Transport, { kind: "redirect" }> =>
    t.kind === "redirect",
  );
  if (redirect) {
    let returnOrigin: string;
    let rpOrigin: string;
    try {
      returnOrigin = new URL(redirect.returnUrl).origin;
      rpOrigin = new URL(params.rpOrigin).origin;
    } catch (e) {
      return {
        ok: false,
        reason: "no_transport_available",
        tried: [
          { transport: "redirect", reason: `invalid url: ${(e as Error).message}` },
        ],
      };
    }
    if (returnOrigin !== rpOrigin) {
      return {
        ok: false,
        reason: "no_transport_available",
        tried: [
          {
            transport: "redirect",
            reason: `returnUrl origin (${returnOrigin}) does not match rpOrigin (${rpOrigin})`,
          },
        ],
      };
    }
  }

  // Build the request once. If any transport is `redirect`, set the
  // request's return_url to that transport's returnUrl (the protocol
  // requires return_url to be present for redirect; absent for popup).
  let request: RpVerifyRequest;
  try {
    request = buildRpVerifyRequest({
      rpOrigin: params.rpOrigin,
      rpName: params.rpName,
      scope: params.scope,
      candidatePhoneE164: params.candidatePhoneE164 ?? null,
      ttlSec: params.ttlSec,
      returnUrl: redirect?.returnUrl,
    });
  } catch (e) {
    return {
      ok: false,
      reason: "no_transport_available",
      tried: [{ transport: params.transports[0]!.kind, reason: `invalid request params: ${(e as Error).message}` }],
    };
  }

  const tried: Array<{ transport: Transport["kind"]; reason: string }> = [];
  const ctx = { request, rpOrigin: params.rpOrigin, windowRef: params.windowRef };

  for (const transport of params.transports) {
    let outcome: TransportOutcome;
    try {
      switch (transport.kind) {
        case "popup":     outcome = await dispatchPopup(transport, ctx); break;
        case "extension": outcome = await dispatchExtension(transport, ctx); break;
        case "redirect":  outcome = await dispatchRedirect(transport, ctx); break;
        case "qr":        outcome = await dispatchQr(transport, ctx); break;
      }
    } catch (e) {
      // Defensive: a transport implementation should never throw — but
      // if one does (bad URL, callback error, etc.), treat it as
      // unavailable so the dispatcher can fall through.
      outcome = { kind: "unavailable", reason: `transport threw: ${(e as Error).message}` };
    }

    switch (outcome.kind) {
      case "unavailable":
        tried.push({ transport: transport.kind, reason: outcome.reason });
        continue;
      case "timeout":
        return { ok: false, reason: "timeout", transport: transport.kind };
      case "navigated":
        return { ok: false, reason: "navigated", transport: "redirect", request };
      case "got_response": {
        const verified = await verifyResponse(
          request,
          outcome.response,
          params,
        );
        return verified.ok
          ? { ok: true, transport: transport.kind, result: verified.result, response: verified.response }
          : verified.kind === "declined"
            ? { ok: false, reason: "declined", transport: transport.kind, error: verified.error }
            : { ok: false, reason: "verification_failed", transport: transport.kind, error: verified.error };
      }
    }
  }

  return { ok: false, reason: "no_transport_available", tried };
}

type VerifyOutcome =
  | { ok: true; result: VerifyRpResponseResult; response: RpVerifyResponse }
  | { ok: false; kind: "declined"; error: string }
  | { ok: false; kind: "verification_failed"; error: string };

async function verifyResponse(
  request: RpVerifyRequest,
  response: RpVerifyResponse | RpVerifyErrorResponse,
  params: RequestAttestationParams,
): Promise<VerifyOutcome> {
  if ("error" in response) {
    return { ok: false, kind: "declined", error: response.error };
  }

  const nonceStore = params.nonceStore ?? new InMemoryNonceStore();
  try {
    const result = await verifyRpVerifyResponse({
      request,
      response,
      options: {
        allowedIssuers: params.trustPolicy.allowedIssuers,
        maxAttestationAgeSec:
          params.trustPolicy.maxAttestationAgeSec ?? 60 * 60 * 24 * 365,
        clockSkewSec: params.trustPolicy.clockSkewSec ?? 60,
      },
      getIssuerPubkey: params.getIssuerPubkey,
      nonceStore,
    });
    return { ok: true, result, response };
  } catch (e) {
    const msg =
      e instanceof ProtocolError ? `${e.code}: ${e.message}` : (e as Error).message;
    return { ok: false, kind: "verification_failed", error: msg };
  }
}
