import { z } from "zod";
import { sha256 } from "@noble/hashes/sha2.js";
import * as ed from "@noble/ed25519";

/* -------------------------------------------------------------------------- */
/* Versioning                                                                 */
/* -------------------------------------------------------------------------- */

export const NUMKEYS_PROTOCOL_VERSION = "1.2";
/**
 * Identifies the wire contract between an embedding application (RP or
 * first-party site) and the wallet PWA. v2 adds the third-party RP
 * verification flow defined in SPEC.md §9. v1 (challenge/response with
 * `service_id` + `callback_url`) is deprecated but still parseable.
 */
export const WALLET_SDK_CONTRACT_VERSION = "wallet-sdk/v2";

/* -------------------------------------------------------------------------- */
/* Encoding helpers                                                           */
/* -------------------------------------------------------------------------- */

const enc = new TextEncoder();

export function bytesToB64Url(bytes: Uint8Array): string {
  let s = "";
  for (const b of bytes) s += String.fromCharCode(b);
  return btoa(s).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
}

export function b64UrlToBytes(s: string): Uint8Array {
  const pad = s.length % 4 === 0 ? "" : "=".repeat(4 - (s.length % 4));
  const b64 = s.replace(/-/g, "+").replace(/_/g, "/") + pad;
  const bin = atob(b64);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}

export function bytesToHex(bytes: Uint8Array): string {
  let s = "";
  for (const b of bytes) s += b.toString(16).padStart(2, "0");
  return s;
}

/* -------------------------------------------------------------------------- */
/* Phone normalization + hashing                                              */
/* -------------------------------------------------------------------------- */

/** Normalize an E.164 phone number for hashing: strip "+" and any non-digits. */
export function normalizePhone(e164: string): string {
  return e164.replace(/[^0-9]/g, "");
}

/** Returns "sha256:<hex>" of normalized phone digits. */
export function phoneHash(e164: string): string {
  const digits = normalizePhone(e164);
  const h = sha256(enc.encode(digits));
  return `sha256:${bytesToHex(h)}`;
}

/* -------------------------------------------------------------------------- */
/* Canonical binding string                                                   */
/* -------------------------------------------------------------------------- */

/**
 * Canonical bytes the issuer signs to produce `binding_proof`, per the
 * numkeys-protocol v1.1 spec (also implemented by the upstream Rust
 * `numkeys-core` crate at `crates/numkeys-crypto/src/hashing.rs`):
 *
 *   numkeys-binding|{iss}|{sub}|{phone_hash}|{user_pubkey}|{nonce}|{iat}|{jti}
 *
 * Demo vs live separation is provided by the `iss` claim
 * (`demo.numkeys.com` vs `numkeys.com`) — it is part of the binding string
 * itself, so a demo binding proof cannot be replayed as a live one as long
 * as the two issuers use distinct domains.
 */
export function canonicalBindingString(p: {
  iss: string;
  sub: string;
  phoneHash: string;
  userPubkey: string;
  nonce: string;
  iat: number;
  jti: string;
}): string {
  return `numkeys-binding|${p.iss}|${p.sub}|${p.phoneHash}|${p.userPubkey}|${p.nonce}|${p.iat}|${p.jti}`;
}

/* -------------------------------------------------------------------------- */
/* Attestation parsing + verification                                         */
/* -------------------------------------------------------------------------- */

export const AttestationClaimsSchema = z.object({
  iss: z.string(),
  sub: z.string(),
  iat: z.number(),
  jti: z.string(),
  phone_hash: z.string().regex(/^sha256:[0-9a-f]{64}$/),
  user_pubkey: z.string(),
  binding_proof: z.string().regex(/^sig:/),
  nonce: z.string().regex(/^[0-9a-f]{32}$/),
  // `mode` is a Numkeys-specific claim added by orchestrators that need to
  // distinguish demo vs live attestations without parsing the iss domain.
  // Optional because the upstream Rust numkeys-node binary doesn't emit it
  // yet — verifiers should treat iss as the authoritative mode signal:
  // `numkeys.com` ⇒ live, `demo.numkeys.com` ⇒ demo.
  mode: z.enum(["demo", "live"]).optional(),
});

export type AttestationClaims = z.infer<typeof AttestationClaimsSchema>;

export interface ParsedAttestation {
  raw: string;
  header: { alg: string; typ?: string };
  claims: AttestationClaims;
  signature: Uint8Array;
  signingInput: Uint8Array; // header.payload bytes (utf-8)
}

export function parseAttestation(jwt: string): ParsedAttestation {
  const parts = jwt.split(".");
  if (parts.length !== 3) {
    throw new ProtocolError("invalid_attestation_format", "JWT must have 3 parts");
  }
  const [h, p, s] = parts;
  let header: ParsedAttestation["header"];
  let payload: unknown;
  try {
    header = JSON.parse(new TextDecoder().decode(b64UrlToBytes(h!)));
    payload = JSON.parse(new TextDecoder().decode(b64UrlToBytes(p!)));
  } catch {
    throw new ProtocolError("invalid_attestation_format", "Invalid base64url JSON");
  }
  if (header.alg !== "EdDSA") {
    throw new ProtocolError("invalid_attestation_format", `Unsupported alg: ${header.alg}`);
  }
  const claims = AttestationClaimsSchema.parse(payload);
  const signature = b64UrlToBytes(s!);
  const signingInput = enc.encode(`${h}.${p}`);
  return { raw: jwt, header, claims, signature, signingInput };
}

/** Verify the JWT's Ed25519 signature against the issuer public key (base64url). */
export async function verifyAttestationSignature(
  parsed: ParsedAttestation,
  issuerPubkeyB64Url: string,
): Promise<boolean> {
  const pub = b64UrlToBytes(issuerPubkeyB64Url);
  return ed.verifyAsync(parsed.signature, parsed.signingInput, pub);
}

/**
 * Verify the binding_proof: an Ed25519 signature by the issuer over the
 * canonical binding string.
 */
export async function verifyBindingProof(
  parsed: ParsedAttestation,
  issuerPubkeyB64Url: string,
): Promise<boolean> {
  const c = parsed.claims;
  const sig = b64UrlToBytes(c.binding_proof.replace(/^sig:/, ""));
  const msg = enc.encode(
    canonicalBindingString({
      iss: c.iss,
      sub: c.sub,
      phoneHash: c.phone_hash,
      userPubkey: c.user_pubkey,
      nonce: c.nonce,
      iat: c.iat,
      jti: c.jti,
    }),
  );
  const pub = b64UrlToBytes(issuerPubkeyB64Url);
  return ed.verifyAsync(sig, msg, pub);
}

/* -------------------------------------------------------------------------- */
/* Challenge response (wallet-side, used by services)                         */
/* -------------------------------------------------------------------------- */

export const ChallengeSchema = z.object({
  proxy_number: z.string(),
  service_id: z.string(),
  challenge_nonce: z.string().regex(/^[0-9a-f]{32}$/),
  verification_id: z.string(),
  expires_at: z.number(),
  callback_url: z.string().url().nullable().optional(),
});
export type Challenge = z.infer<typeof ChallengeSchema>;

export const ChallengeResponsePayloadSchema = z.object({
  service_id: z.string(),
  challenge_nonce: z.string(),
  response_nonce: z.string(),
  verification_id: z.string(),
  timestamp: z.number(),
});
export type ChallengeResponsePayload = z.infer<typeof ChallengeResponsePayloadSchema>;

/**
 * Deterministic JSON canonicalizer: keys sorted lexicographically, no whitespace.
 * Used for signing challenge responses.
 */
export function canonicalJson(value: unknown): string {
  if (value === null || typeof value !== "object") return JSON.stringify(value);
  if (Array.isArray(value)) return `[${value.map(canonicalJson).join(",")}]`;
  const keys = Object.keys(value as Record<string, unknown>).sort();
  return `{${keys
    .map((k) => `${JSON.stringify(k)}:${canonicalJson((value as Record<string, unknown>)[k])}`)
    .join(",")}}`;
}

/* -------------------------------------------------------------------------- */
/* Errors                                                                     */
/* -------------------------------------------------------------------------- */

export type ProtocolErrorCode =
  | "invalid_attestation_format"
  | "invalid_attestation_signature"
  | "invalid_binding_proof"
  | "issuer_key_discovery_failed"
  | "challenge_parse_failed"
  | "challenge_validation_failed"
  | "signing_failed"
  | "verification_failed"
  // SPEC.md §10 — RP verification flow (v1.2)
  | "version_mismatch"
  | "request_expired"
  | "invalid_response_format"
  | "request_id_mismatch"
  | "origin_mismatch"
  | "nonce_mismatch"
  | "nonce_replay"
  | "response_expired"
  | "response_from_future"
  | "invalid_holder_signature"
  | "jti_mismatch"
  | "proxy_number_mismatch"
  | "scope_mismatch"
  | "phone_match_lie"
  | "phone_does_not_match"
  | "attestation_expired"
  | "issuer_not_allowed"
  | "user_declined";

export class ProtocolError extends Error {
  constructor(
    public code: ProtocolErrorCode,
    message: string,
  ) {
    super(message);
    this.name = "ProtocolError";
  }
}

/* -------------------------------------------------------------------------- */
/* Orchestration API DTOs (shared between api-server and wallet)              */
/* -------------------------------------------------------------------------- */

export const IssuanceModeSchema = z.enum(["demo", "live"]);
export type IssuanceMode = z.infer<typeof IssuanceModeSchema>;

export const SessionStateSchema = z.enum([
  "pending",
  "phone_pending",
  "phone_verified",
  "payment_pending",
  "paid",
  // Transient claim state — set atomically when finalize() begins minting,
  // released to "finalized" on success or "failed" on error. Exists solely
  // so concurrent finalize requests can't double-issue.
  "issuing",
  "finalized",
  "failed",
  "expired",
]);
export type SessionState = z.infer<typeof SessionStateSchema>;

export const StartIssuanceRequestSchema = z.object({
  mode: IssuanceModeSchema,
  scope: z.string().regex(/^\d{1,4}$/, "scope must be 1-4 digit country code"),
  user_pubkey: z.string().min(1),
  phone_e164: z.string().regex(/^\+[1-9]\d{6,14}$/, "must be E.164"),
});
export type StartIssuanceRequest = z.infer<typeof StartIssuanceRequestSchema>;

export const VerifyPhoneRequestSchema = z.object({
  code: z.string().min(4),
});
export type VerifyPhoneRequest = z.infer<typeof VerifyPhoneRequestSchema>;

export const SessionViewSchema = z.object({
  id: z.string().uuid(),
  state: SessionStateSchema,
  mode: IssuanceModeSchema,
  scope: z.string(),
  user_pubkey: z.string(),
  proxy_number: z.string().nullable(),
  attestation: z.string().nullable(),
  payment_required: z.boolean(),
  payment_status: z.string().nullable(),
  payment: z
    .object({
      // Vendor identifier intentionally omitted from the public view —
      // operators may swap providers without leaking the choice to the
      // wallet. The wallet only needs the rails it must render (BOLT11
      // and/or hosted checkout URL) and the price.
      amount_usd: z.string(),
      checkout_url: z.string().nullable(),
      lightning_invoice: z.string().nullable(),
    })
    .nullable()
    .optional(),
  error: z.string().nullable(),
  created_at: z.string(),
});
export type SessionView = z.infer<typeof SessionViewSchema>;

export const IssuerPubkeyResponseSchema = z.object({
  issuer: z.string(),
  /** Allow-list of acceptable `iss` values served by this issuer key
   * (e.g. ["numkeys.com", "demo.numkeys.com"]). Optional for backward
   * compatibility; clients should fall back to [`issuer`]. */
  issuers: z.array(z.string()).optional(),
  public_key: z.string(),
  alg: z.literal("EdDSA"),
});
export type IssuerPubkeyResponse = z.infer<typeof IssuerPubkeyResponseSchema>;

/**
 * Wallet-facing issuer config. Intentionally minimal — exposes only
 * what the UI needs to render correct affordances. Internal vendor
 * names (termii/twilio/bitnob), per-mode issuer domains, sidecar
 * topology, and pricing are NOT exposed here; they're operator
 * concerns and would otherwise leak through XHR responses.
 */
export const ConfigResponseSchema = z.object({
  /** The canonical issuer hostname this server is currently signing as. */
  issuer_domain: z.string(),
  /** Whether issuance requires a payment step (live mode only). */
  payments_enabled: z.boolean(),
  /** Whether the manual "I have paid" testing bypass is offered. */
  payment_bypass_available: z.boolean(),
  /** Whether live (real-SMS) issuance is available on this issuer. */
  live_mode_available: z.boolean(),
  /**
   * True when the configured phone verifier is the in-process demo
   * (no real SMS is sent). The wallet uses this to display a hint
   * if a user picks "live" against a demo-only deployment.
   */
  demo_phone_provider: z.boolean(),
});
export type ConfigResponse = z.infer<typeof ConfigResponseSchema>;

/* -------------------------------------------------------------------------- */
/* Third-party RP verification flow (SPEC.md §9, v1.2)                        */
/* -------------------------------------------------------------------------- */

/**
 * Generate a 16-byte random nonce as 32 lowercase hex characters,
 * matching the format defined in SPEC.md §3.
 */
export function randomNonce(): string {
  const bytes = new Uint8Array(16);
  // Works in Node 19+ and all modern browsers.
  globalThis.crypto.getRandomValues(bytes);
  return bytesToHex(bytes);
}

const RpScopeSchema = z.enum(["anonymous", "phone"]);
export type RpScope = z.infer<typeof RpScopeSchema>;

const E164Regex = /^\+[1-9]\d{6,14}$/;
const NonceRegex = /^[0-9a-f]{32}$/;
const HttpsOriginRegex = /^https:\/\/[^\s/?#]+$/;

/** SPEC.md §9.3 — VerifyRequest wire schema (RP → Wallet). */
export const RpVerifyRequestSchema = z
  .object({
    v: z.literal(WALLET_SDK_CONTRACT_VERSION),
    request_id: z.string().regex(NonceRegex),
    rp_origin: z.string().regex(HttpsOriginRegex, "rp_origin must be https origin"),
    rp_name: z.string().min(1).max(80),
    nonce: z.string().regex(NonceRegex),
    iat: z.number().int(),
    expires_at: z.number().int(),
    scope: RpScopeSchema,
    candidate_phone_e164: z.string().regex(E164Regex).nullable(),
    return_url: z.string().url().nullable(),
  })
  .refine((r) => r.expires_at - r.iat <= 300, {
    message: "expires_at - iat MUST be ≤ 300 seconds",
    path: ["expires_at"],
  })
  .refine(
    (r) => (r.scope === "phone" ? r.candidate_phone_e164 !== null : r.candidate_phone_e164 === null),
    { message: "candidate_phone_e164 presence MUST match scope", path: ["candidate_phone_e164"] },
  );
export type RpVerifyRequest = z.infer<typeof RpVerifyRequestSchema>;

/** SPEC.md §9.4 — payload signed by the holder. */
export const RpVerifyResponsePayloadSchema = z
  .object({
    v: z.literal(WALLET_SDK_CONTRACT_VERSION),
    request_id: z.string().regex(NonceRegex),
    rp_origin: z.string().regex(HttpsOriginRegex),
    nonce: z.string().regex(NonceRegex),
    attestation_jti: z.string().min(1),
    proxy_number: z.string().min(1),
    iat: z.number().int(),
    scope: RpScopeSchema,
    candidate_phone_match: z.boolean().nullable(),
  })
  .refine(
    (p) =>
      p.scope === "phone"
        ? typeof p.candidate_phone_match === "boolean"
        : p.candidate_phone_match === null,
    { message: "candidate_phone_match shape MUST match scope", path: ["candidate_phone_match"] },
  );
export type RpVerifyResponsePayload = z.infer<typeof RpVerifyResponsePayloadSchema>;

/** SPEC.md §9.4 — successful VerifyResponse wire schema (Wallet → RP). */
export const RpVerifyResponseSchema = z.object({
  v: z.literal(WALLET_SDK_CONTRACT_VERSION),
  request_id: z.string().regex(NonceRegex),
  attestation: z.string().min(1),
  issuer: z.string().min(1),
  signed_response: z.object({
    payload: RpVerifyResponsePayloadSchema,
    signature: z.string().regex(/^sig:[A-Za-z0-9_-]+$/),
  }),
});
export type RpVerifyResponse = z.infer<typeof RpVerifyResponseSchema>;

/** SPEC.md §9.4 — declined / error response. */
export const RpVerifyErrorResponseSchema = z.object({
  v: z.literal(WALLET_SDK_CONTRACT_VERSION),
  request_id: z.string().regex(NonceRegex),
  error: z.string(),
});
export type RpVerifyErrorResponse = z.infer<typeof RpVerifyErrorResponseSchema>;

/* ---- RP-side: build a request ------------------------------------------ */

export interface BuildRpVerifyRequestParams {
  rpOrigin: string;
  rpName: string;
  scope: RpScope;
  candidatePhoneE164?: string | null;
  returnUrl?: string | null;
  /** Seconds until expiry. Default 120, MUST be ≤ 300 per SPEC.md §9.3. */
  ttlSec?: number;
  now?: () => number;
}

/**
 * RP-side helper that produces a syntactically valid VerifyRequest with a
 * fresh `request_id`, fresh `nonce`, and consistent timing fields. The
 * caller MUST persist the returned object until the response is verified
 * (the verifier needs `request_id`, `nonce`, `rp_origin`, `expires_at`,
 * and the original `scope` / `candidate_phone_e164` to enforce binding).
 */
export function buildRpVerifyRequest(params: BuildRpVerifyRequestParams): RpVerifyRequest {
  const ttl = params.ttlSec ?? 120;
  if (ttl <= 0 || ttl > 300) {
    throw new ProtocolError("invalid_response_format", "ttlSec must be in (0, 300]");
  }
  const now = (params.now ?? (() => Math.floor(Date.now() / 1000)))();
  const candidate = params.candidatePhoneE164 ?? null;
  const req: RpVerifyRequest = RpVerifyRequestSchema.parse({
    v: WALLET_SDK_CONTRACT_VERSION,
    request_id: randomNonce(),
    rp_origin: params.rpOrigin,
    rp_name: params.rpName,
    nonce: randomNonce(),
    iat: now,
    expires_at: now + ttl,
    scope: params.scope,
    candidate_phone_e164: params.scope === "phone" ? candidate : null,
    return_url: params.returnUrl ?? null,
  });
  return req;
}

/**
 * Encode a VerifyRequest for the wallet popup URL `?req=` query parameter
 * (SPEC.md §9.5.1). The encoding is b64url(canonical_json(request)).
 */
export function encodeRpVerifyRequest(request: RpVerifyRequest): string {
  return bytesToB64Url(enc.encode(canonicalJson(request)));
}

/**
 * Decode the popup `?req=` query parameter. Wallet-side entry point per
 * SPEC.md §9.9.1 step 1. Throws ProtocolError("invalid_response_format")
 * if the payload is not valid b64url canonical JSON of the schema.
 */
export function decodeRpVerifyRequest(encoded: string): RpVerifyRequest {
  let json: unknown;
  try {
    json = JSON.parse(new TextDecoder().decode(b64UrlToBytes(encoded)));
  } catch {
    throw new ProtocolError("invalid_response_format", "req is not valid b64url JSON");
  }
  const parsed = RpVerifyRequestSchema.safeParse(json);
  if (!parsed.success) {
    throw new ProtocolError("invalid_response_format", parsed.error.message);
  }
  return parsed.data;
}

/* ---- Wallet-side: validate request and sign response ------------------ */

export interface ValidateRpRequestOptions {
  /** Tolerance in seconds for `iat` in the future (default 60). */
  clockSkewSec?: number;
  now?: () => number;
}

/**
 * Wallet-side request validation per SPEC.md §9.9.1. MUST run before the
 * consent prompt is shown. Throws on any violation.
 */
export function validateRpVerifyRequest(
  request: RpVerifyRequest,
  options: ValidateRpRequestOptions = {},
): void {
  const skew = options.clockSkewSec ?? 60;
  const now = (options.now ?? (() => Math.floor(Date.now() / 1000)))();
  if (request.iat > now + skew) {
    throw new ProtocolError("response_from_future", "request iat is too far in the future");
  }
  if (now > request.expires_at) {
    throw new ProtocolError("request_expired", "request expired before consent");
  }
}

export interface SignRpVerifyResponseParams {
  request: RpVerifyRequest;
  /** The full attestation JWT being presented. */
  attestation: string;
  /** Holder's Ed25519 private key (32 raw bytes). */
  holderPrivateKey: Uint8Array;
  now?: () => number;
}

/**
 * Wallet-side: produce a signed VerifyResponse per SPEC.md §9.4 and §9.6.
 *
 * Caller MUST have already obtained explicit user consent (§9.7) and MUST
 * have validated the request via `validateRpVerifyRequest` (§9.9.1).
 *
 * For `scope = "phone"` the wallet asserts a candidate-match boolean by
 * recomputing the phone hash itself; the value is informational only —
 * the RP recomputes the same hash in §9.9 step 8 and rejects on mismatch.
 */
export async function signRpVerifyResponse(
  params: SignRpVerifyResponseParams,
): Promise<RpVerifyResponse> {
  const { request, attestation: jwt, holderPrivateKey } = params;
  const parsedAtt = parseAttestation(jwt);
  const claims = parsedAtt.claims;

  // Sanity: the holder key the wallet is signing with MUST match the
  // attestation's user_pubkey. This catches wallet bugs (wrong account
  // selected) before producing a response that will fail RP verification.
  const expectedPubB64 = claims.user_pubkey;
  let derivedPub: Uint8Array;
  try {
    derivedPub = await ed.getPublicKeyAsync(holderPrivateKey);
  } catch (err) {
    throw new ProtocolError("signing_failed", `derive pubkey: ${(err as Error).message}`);
  }
  if (bytesToB64Url(derivedPub) !== expectedPubB64) {
    throw new ProtocolError("signing_failed", "holder key does not match attestation user_pubkey");
  }

  let candidateMatch: boolean | null;
  if (request.scope === "phone") {
    if (!request.candidate_phone_e164) {
      // Should be impossible thanks to the schema refine, but defend anyway.
      throw new ProtocolError("invalid_response_format", "phone scope without candidate");
    }
    candidateMatch = phoneHash(request.candidate_phone_e164) === claims.phone_hash;
  } else {
    candidateMatch = null;
  }

  const now = (params.now ?? (() => Math.floor(Date.now() / 1000)))();
  const payload: RpVerifyResponsePayload = RpVerifyResponsePayloadSchema.parse({
    v: WALLET_SDK_CONTRACT_VERSION,
    request_id: request.request_id,
    rp_origin: request.rp_origin,
    nonce: request.nonce,
    attestation_jti: claims.jti,
    proxy_number: claims.sub,
    iat: now,
    scope: request.scope,
    candidate_phone_match: candidateMatch,
  });

  let sig: Uint8Array;
  try {
    sig = await ed.signAsync(enc.encode(canonicalJson(payload)), holderPrivateKey);
  } catch (err) {
    throw new ProtocolError("signing_failed", (err as Error).message);
  }

  return {
    v: WALLET_SDK_CONTRACT_VERSION,
    request_id: request.request_id,
    attestation: jwt,
    issuer: claims.iss,
    signed_response: {
      payload,
      signature: `sig:${bytesToB64Url(sig)}`,
    },
  };
}

/* ---- RP-side: verifier (SPEC.md §9.9) ---------------------------------- */

/**
 * Pluggable nonce store. The verifier consumes the nonce only after every
 * crypto check has passed (SPEC.md §9.9 Step 9), so an attacker who
 * submits invalid responses cannot burn legitimate nonces.
 */
export interface NonceStore {
  /** Returns true iff the nonce has previously been marked. */
  has(nonce: string): Promise<boolean> | boolean;
  /** Mark `nonce` as consumed for at least `ttlSec` seconds. */
  mark(nonce: string, ttlSec: number): Promise<void> | void;
}

/**
 * Pluggable issuer-pubkey resolver. Implementations are responsible for:
 *  - HTTPS + valid TLS to `https://{iss}/.well-known/numkeys/issuer-pubkey.json`
 *  - SSRF protection: refuse to fetch hosts that resolve to private,
 *    loopback, link-local, or IPv6 unique-local addresses (SPEC.md §9.9
 *    Step 4 normative requirement).
 *  - Caching policy (SPEC.md §6: at least 1 hour, refresh on verify failure).
 *
 * Returning `null` indicates discovery failure and triggers
 * `issuer_key_discovery_failed`.
 */
export type IssuerPubkeyResolver = (iss: string) => Promise<string | null>;

export interface VerifyRpResponseOptions {
  /** Allow-list checked BEFORE any network fetch (SPEC.md §9.9 Step 3). */
  allowedIssuers: string[];
  /** Reject attestations older than this. */
  maxAttestationAgeSec: number;
  /** Tolerance for response.iat in the future (default 60). */
  clockSkewSec?: number;
  now?: () => number;
}

export interface VerifyRpResponseResult {
  proxyNumber: string;
  issuer: string;
  attestationJti: string;
  phoneVerified: boolean;
}

/**
 * RP-side verifier. Implements SPEC.md §9.9 verbatim.
 *
 * Throws ProtocolError with the spec's error code on any failed check.
 * Returns the verified facts (proxy_number, issuer, jti, phoneVerified)
 * on success.
 */
export async function verifyRpVerifyResponse(args: {
  request: RpVerifyRequest;
  response: RpVerifyResponse;
  options: VerifyRpResponseOptions;
  getIssuerPubkey: IssuerPubkeyResolver;
  nonceStore: NonceStore;
}): Promise<VerifyRpResponseResult> {
  const { request, response, options, getIssuerPubkey, nonceStore } = args;
  const skew = options.clockSkewSec ?? 60;
  const now = (options.now ?? (() => Math.floor(Date.now() / 1000)))();

  // 1. Outer wire format and request liveness
  if (response.v !== WALLET_SDK_CONTRACT_VERSION) {
    throw new ProtocolError("version_mismatch", `response.v != ${WALLET_SDK_CONTRACT_VERSION}`);
  }
  if (response.request_id !== request.request_id) {
    throw new ProtocolError("request_id_mismatch", "response.request_id");
  }
  if (now > request.expires_at) {
    throw new ProtocolError("request_expired", "request.expires_at < now");
  }

  // 2. Inner payload schema (zod refine() already enforces shape on parse,
  //    but we re-validate here in case the response was constructed by a
  //    caller that bypassed the schema).
  const payloadParsed = RpVerifyResponsePayloadSchema.safeParse(response.signed_response.payload);
  if (!payloadParsed.success) {
    throw new ProtocolError("invalid_response_format", payloadParsed.error.message);
  }
  const payload = payloadParsed.data;
  if (payload.v !== WALLET_SDK_CONTRACT_VERSION) {
    throw new ProtocolError("version_mismatch", "payload.v");
  }
  if (payload.request_id !== request.request_id) {
    throw new ProtocolError("request_id_mismatch", "payload.request_id");
  }
  if (payload.rp_origin !== request.rp_origin) {
    throw new ProtocolError("origin_mismatch", "payload.rp_origin");
  }
  if (payload.nonce !== request.nonce) {
    throw new ProtocolError("nonce_mismatch", "payload.nonce");
  }
  if (payload.iat > now + skew) {
    throw new ProtocolError("response_from_future", "payload.iat too far in future");
  }
  if (payload.iat < now - 300) {
    throw new ProtocolError("response_expired", "payload.iat too old");
  }
  if (payload.scope !== request.scope) {
    throw new ProtocolError("scope_mismatch", "payload.scope != request.scope");
  }

  // 3. Issuer allow-list — BEFORE any network fetch (SSRF defense).
  const attestation = parseAttestation(response.attestation);
  if (!options.allowedIssuers.includes(attestation.claims.iss)) {
    throw new ProtocolError("issuer_not_allowed", attestation.claims.iss);
  }

  // 4. Issuer key fetch — only reached after iss is in the allow-list.
  const issuerPubkey = await getIssuerPubkey(attestation.claims.iss);
  if (!issuerPubkey) {
    throw new ProtocolError("issuer_key_discovery_failed", attestation.claims.iss);
  }

  // 5. Cryptographic verification of the attestation
  if (!(await verifyAttestationSignature(attestation, issuerPubkey))) {
    throw new ProtocolError("invalid_attestation_signature", "attestation JWT signature");
  }
  if (!(await verifyBindingProof(attestation, issuerPubkey))) {
    throw new ProtocolError("invalid_binding_proof", "binding_proof");
  }
  if (now - attestation.claims.iat > options.maxAttestationAgeSec) {
    throw new ProtocolError("attestation_expired", `attestation older than ${options.maxAttestationAgeSec}s`);
  }

  // 6. Cross-binding the response to the attestation
  if (payload.attestation_jti !== attestation.claims.jti) {
    throw new ProtocolError("jti_mismatch", "payload.attestation_jti");
  }
  if (payload.proxy_number !== attestation.claims.sub) {
    throw new ProtocolError("proxy_number_mismatch", "payload.proxy_number");
  }

  // 7. Holder signature on response
  const sigB64 = response.signed_response.signature.replace(/^sig:/, "");
  const sig = b64UrlToBytes(sigB64);
  const userPub = b64UrlToBytes(attestation.claims.user_pubkey);
  const msg = enc.encode(canonicalJson(payload));
  if (!(await ed.verifyAsync(sig, msg, userPub))) {
    throw new ProtocolError("invalid_holder_signature", "ed25519 verify failed");
  }

  // 8. Scope-specific checks (recompute hash; wallet bool is informational).
  if (request.scope === "phone") {
    if (!request.candidate_phone_e164) {
      throw new ProtocolError("invalid_response_format", "request.candidate_phone_e164 missing");
    }
    const expectedHash = phoneHash(request.candidate_phone_e164);
    const actualMatch = expectedHash === attestation.claims.phone_hash;
    if (payload.candidate_phone_match !== actualMatch) {
      throw new ProtocolError("phone_match_lie", "wallet asserted incorrect candidate_phone_match");
    }
    if (!actualMatch) {
      throw new ProtocolError("phone_does_not_match", "candidate phone hash does not match attestation");
    }
  }

  // 9. Consume the nonce — LAST, only after every crypto check passed.
  if (await nonceStore.has(payload.nonce)) {
    throw new ProtocolError("nonce_replay", payload.nonce);
  }
  const ttlSec = Math.max(600, request.expires_at - now + 60);
  await nonceStore.mark(payload.nonce, ttlSec);

  return {
    proxyNumber: payload.proxy_number,
    issuer: attestation.claims.iss,
    attestationJti: attestation.claims.jti,
    phoneVerified: request.scope === "phone",
  };
}

/**
 * Convenience in-memory NonceStore. Suitable for development and tests;
 * production RPs SHOULD back this with a shared store (Redis, DB) so that
 * replay protection survives process restarts and works across replicas.
 */
export class InMemoryNonceStore implements NonceStore {
  private readonly seen = new Map<string, number>();
  has(nonce: string): boolean {
    const exp = this.seen.get(nonce);
    if (exp === undefined) return false;
    if (exp < Math.floor(Date.now() / 1000)) {
      this.seen.delete(nonce);
      return false;
    }
    return true;
  }
  mark(nonce: string, ttlSec: number): void {
    this.seen.set(nonce, Math.floor(Date.now() / 1000) + ttlSec);
  }
}
