/**
 * Transport implementations for `requestAttestation`.
 *
 * Each transport has the same job: get a signed VerifyResponse (or a
 * structured error response) back from a wallet. They differ only in HOW
 * they reach the wallet — popup window, browser extension, mobile deep
 * link, or QR-code-mediated cross-device flow.
 *
 * The dispatcher (request-attestation.ts) tries transports in order and
 * stops at the first one that produces a response (success OR a
 * deliberate user decline). Transports that can't even start — popup
 * blocked, no extension installed — return `{ kind: "unavailable" }` so
 * the dispatcher can fall through to the next one.
 *
 * NB: All transports share one strict invariant — the response they
 * yield is unverified. The dispatcher runs the SPEC §9.9 verifier on
 * whatever they hand back, regardless of transport.
 */

import {
  encodeRpVerifyRequest,
  RpVerifyResponseSchema,
  RpVerifyErrorResponseSchema,
  bytesToB64Url,
  b64UrlToBytes,
  type RpVerifyRequest,
  type RpVerifyResponse,
  type RpVerifyErrorResponse,
} from "@workspace/numkeys-protocol";

// ── Public types ──────────────────────────────────────────────────────────

/**
 * A transport tells the SDK HOW to deliver the request to a wallet and
 * receive a response. The dispatcher walks an array of these in order.
 */
export type Transport =
  | PopupTransport
  | ExtensionTransport
  | RedirectTransport
  | QrTransport;

export interface PopupTransport {
  kind: "popup";
  /**
   * The wallet's verify URL, e.g. "https://numkeys.com/wallet/verify".
   * In a wallet-discovery world this might come from user settings; the
   * SDK doesn't take a position on where you get it.
   */
  walletUrl: string;
  /** window.open features. Default `popup,width=480,height=720`. */
  popupFeatures?: string;
  /** Total wait before resolving with `timeout`. Default 5 minutes. */
  timeoutMs?: number;
}

export interface ExtensionTransport {
  kind: "extension";
  /**
   * Probe budget — how long to wait for a `numkeys/sign-ack` from a
   * browser extension before declaring it `unavailable` and falling
   * through to the next transport. Default 200ms.
   */
  probeTimeoutMs?: number;
  /**
   * Total wait for the extension's actual response after it has acked.
   * Default 5 minutes (extensions may pop their own UI).
   */
  responseTimeoutMs?: number;
}

export interface RedirectTransport {
  kind: "redirect";
  walletUrl: string;
  /** Where the wallet should send the user back to. MUST be on rpOrigin. */
  returnUrl: string;
  /**
   * Redirect transport's "response" arrives on a NEXT page load via
   * `consumeRedirectFragment`, not on the current page. When this
   * transport runs, it persists the request via this storage callback
   * and navigates the top-level window. The dispatcher then resolves
   * with a special `kind: "navigated"` outcome that the caller is
   * expected to handle by calling `consumeRedirectFragment` on the
   * return page. Most apps prefer popup or QR for this reason.
   */
  persistRequest?: (request: RpVerifyRequest) => void;
}

export interface QrTransport {
  kind: "qr";
  /**
   * Called once when QR transport starts. Your server creates a
   * one-shot session and returns the URLs needed to coordinate.
   */
  createSession: () => Promise<QrSession>;
  /**
   * Called with the QR payload (a deep-link URL containing the encoded
   * request and session ID) so you can render it in your UI. Whatever
   * you return is invoked when the transport finishes (success, error,
   * timeout) so you can dismiss the QR modal.
   */
  displayQr: (qrPayload: string) => Promise<void> | void;
  /** Called on settle — for cleaning up the QR UI. */
  dismissQr?: () => void;
  /** How often to poll the session for a response. Default 1500ms. */
  pollIntervalMs?: number;
  /** Total wait before timing out. Default 5 minutes. */
  timeoutMs?: number;
}

/**
 * Server-provided rendezvous URLs for QR transport. The wallet POSTs
 * the response to `signResponseUrl`; the browser polls `pollUrl` for it.
 */
export interface QrSession {
  /**
   * URL embedded in the QR code. Wallets dereference this to get the
   * encoded request (and to know where to POST their response).
   * Typically `https://your-rp.com/numkeys/sessions/<sid>`.
   */
  signRequestUrl: string;
  /** The browser polls this until a response arrives. */
  pollUrl: string;
}

/**
 * Result of running one transport.
 *
 *  - `got_response`  — wallet returned something (still unverified)
 *  - `unavailable`   — transport couldn't start (extension absent,
 *                      popup blocked, etc.); dispatcher tries next
 *  - `navigated`     — redirect transport handed off to top-level nav
 *  - `timeout`       — transport reached but no response in time
 */
export type TransportOutcome =
  | { kind: "got_response"; response: RpVerifyResponse | RpVerifyErrorResponse }
  | { kind: "unavailable"; reason: string }
  | { kind: "navigated" }
  | { kind: "timeout" };

export interface TransportContext {
  request: RpVerifyRequest;
  rpOrigin: string;
  windowRef?: Window;
}

// ── Popup transport ───────────────────────────────────────────────────────

export async function dispatchPopup(
  t: PopupTransport,
  ctx: TransportContext,
): Promise<TransportOutcome> {
  const w = ctx.windowRef ?? (globalThis as { window?: Window }).window;
  if (!w) return { kind: "unavailable", reason: "no window object (server context)" };

  const url = new URL(t.walletUrl);
  url.searchParams.set("req", encodeRpVerifyRequest(ctx.request));

  const popup = w.open(
    url.toString(),
    "numkeys-verify",
    t.popupFeatures ?? "popup,width=480,height=720",
  );
  if (!popup) return { kind: "unavailable", reason: "popup blocked by browser" };

  const walletOrigin = new URL(t.walletUrl).origin;

  return new Promise<TransportOutcome>((resolve) => {
    let settled = false;
    const settle = (o: TransportOutcome) => {
      if (settled) return;
      settled = true;
      w.removeEventListener("message", onMessage);
      clearInterval(closedPoll);
      clearTimeout(timer);
      resolve(o);
    };

    const onMessage = (ev: MessageEvent) => {
      if (ev.origin !== walletOrigin) return;
      const data = ev.data as { type?: string; response?: unknown };
      if (data?.type !== "numkeys/verify-response") return;

      const okParse = RpVerifyResponseSchema.safeParse(data.response);
      const errParse = RpVerifyErrorResponseSchema.safeParse(data.response);

      if (errParse.success) {
        if (errParse.data.request_id !== ctx.request.request_id) return;
        settle({ kind: "got_response", response: errParse.data });
      } else if (okParse.success && okParse.data.request_id === ctx.request.request_id) {
        settle({ kind: "got_response", response: okParse.data });
      }
    };

    w.addEventListener("message", onMessage);

    const closedPoll = setInterval(() => {
      if (popup.closed) settle({ kind: "unavailable", reason: "user closed popup" });
    }, 500);

    const timer = setTimeout(
      () => {
        try { popup.close(); } catch { /* already closed */ }
        settle({ kind: "timeout" });
      },
      t.timeoutMs ?? 5 * 60 * 1000,
    );
  });
}

// ── Extension transport ───────────────────────────────────────────────────
//
// Wire contract for browser-extension wallets implementing this transport:
//
//   1. Listen on window.message for { type: "numkeys/sign-probe", tx_id }
//      Reply ASAP (<200ms) with { type: "numkeys/sign-ack", tx_id }
//      (echo back the tx_id so the SDK can match probe→ack).
//
//   2. Listen on window.message for
//      { type: "numkeys/sign-request", tx_id, request }
//      Show your in-extension UI, get user consent, sign.
//
//   3. Reply with { type: "numkeys/sign-response", tx_id, request_id, response }
//      where response is either an RpVerifyResponse or RpVerifyErrorResponse.
//
// All messages MUST be posted with targetOrigin === window.location.origin
// (the RP page's origin). All received messages MUST be checked so that
// ev.source === window (i.e. came from the page itself, forwarded by
// the extension's content script).
//
// Security note: postMessage on the page is shared with every script
// running in that document. Any same-origin script can forge ack/decline.
// The tx_id echo raises the bar for cross-request confusion but does not
// — and cannot — defend against a same-origin attacker; that's outside
// the protocol's threat model. The cryptographic verifier in
// `requestAttestation` is the actual integrity boundary.

function randomTxId(): string {
  const bytes = new Uint8Array(16);
  // Node 18+ and all modern browsers expose globalThis.crypto.
  globalThis.crypto.getRandomValues(bytes);
  return bytesToB64Url(bytes);
}

export async function dispatchExtension(
  t: ExtensionTransport,
  ctx: TransportContext,
): Promise<TransportOutcome> {
  const w = ctx.windowRef ?? (globalThis as { window?: Window }).window;
  if (!w) return { kind: "unavailable", reason: "no window object" };

  const txId = randomTxId();

  // Step 1: probe (with tx_id that ack must echo).
  const probed = await new Promise<boolean>((resolve) => {
    let acked = false;
    const onProbeReply = (ev: MessageEvent) => {
      if (ev.source !== w) return;
      const d = ev.data as { type?: string; tx_id?: string };
      if (d?.type === "numkeys/sign-ack" && d.tx_id === txId) {
        acked = true;
        w.removeEventListener("message", onProbeReply);
        resolve(true);
      }
    };
    w.addEventListener("message", onProbeReply);
    w.postMessage({ type: "numkeys/sign-probe", tx_id: txId }, ctx.rpOrigin);
    setTimeout(() => {
      if (!acked) {
        w.removeEventListener("message", onProbeReply);
        resolve(false);
      }
    }, t.probeTimeoutMs ?? 200);
  });

  if (!probed) {
    return { kind: "unavailable", reason: "no extension responded to probe" };
  }

  // Step 2: send the actual sign request.
  return new Promise<TransportOutcome>((resolve) => {
    let settled = false;
    const settle = (o: TransportOutcome) => {
      if (settled) return;
      settled = true;
      w.removeEventListener("message", onResponse);
      clearTimeout(timer);
      resolve(o);
    };

    const onResponse = (ev: MessageEvent) => {
      if (ev.source !== w) return;
      const d = ev.data as {
        type?: string;
        tx_id?: string;
        request_id?: string;
        response?: unknown;
      };
      if (d?.type !== "numkeys/sign-response") return;
      if (d.tx_id !== txId) return;
      if (d.request_id !== ctx.request.request_id) return;

      const okParse = RpVerifyResponseSchema.safeParse(d.response);
      const errParse = RpVerifyErrorResponseSchema.safeParse(d.response);
      if (errParse.success) settle({ kind: "got_response", response: errParse.data });
      else if (okParse.success) settle({ kind: "got_response", response: okParse.data });
      // Malformed messages are ignored — we keep waiting for a valid one
      // until the timeout. Genuine bad responses surface from the verifier.
    };

    w.addEventListener("message", onResponse);
    w.postMessage(
      { type: "numkeys/sign-request", tx_id: txId, request: ctx.request },
      ctx.rpOrigin,
    );

    const timer = setTimeout(
      () => settle({ kind: "timeout" }),
      t.responseTimeoutMs ?? 5 * 60 * 1000,
    );
  });
}

// ── Redirect transport ────────────────────────────────────────────────────

export async function dispatchRedirect(
  t: RedirectTransport,
  ctx: TransportContext,
): Promise<TransportOutcome> {
  const w = ctx.windowRef ?? (globalThis as { window?: Window }).window;
  if (!w) return { kind: "unavailable", reason: "no window object" };

  // The dispatcher is expected to have built `ctx.request` with the
  // right `return_url` already (matching `t.returnUrl`); double-check.
  if (!ctx.request.return_url || new URL(ctx.request.return_url).href !== new URL(t.returnUrl).href) {
    return {
      kind: "unavailable",
      reason: "request.return_url does not match transport.returnUrl",
    };
  }

  if (t.persistRequest) {
    try { t.persistRequest(ctx.request); } catch (e) {
      return { kind: "unavailable", reason: `persistRequest threw: ${(e as Error).message}` };
    }
  }

  const url = new URL(t.walletUrl);
  url.searchParams.set("req", encodeRpVerifyRequest(ctx.request));
  w.location.assign(url.toString());

  // Top-level navigation; we don't get a response on this page.
  return { kind: "navigated" };
}

// ── QR transport ──────────────────────────────────────────────────────────

export async function dispatchQr(
  t: QrTransport,
  ctx: TransportContext,
): Promise<TransportOutcome> {
  let session: QrSession;
  try {
    session = await t.createSession();
  } catch (e) {
    return { kind: "unavailable", reason: `createSession failed: ${(e as Error).message}` };
  }

  const encodedReq = encodeRpVerifyRequest(ctx.request);
  // The QR payload is a wallet deep link the mobile wallet recognizes.
  // We use a "numkeys:" scheme with the session URL + encoded request.
  // Wallets POST their response to `session.signRequestUrl`.
  const qrPayload =
    `numkeys://sign?session=${encodeURIComponent(session.signRequestUrl)}` +
    `&req=${encodedReq}`;

  let dismissed = false;
  const dismiss = () => {
    if (dismissed) return;
    dismissed = true;
    try { t.dismissQr?.(); } catch { /* swallow */ }
  };

  try {
    await t.displayQr(qrPayload);
  } catch (e) {
    dismiss();
    return { kind: "unavailable", reason: `displayQr failed: ${(e as Error).message}` };
  }

  const interval = t.pollIntervalMs ?? 1500;
  const timeout = t.timeoutMs ?? 5 * 60 * 1000;
  const deadline = Date.now() + timeout;

  while (Date.now() < deadline) {
    try {
      const r = await fetch(session.pollUrl, { method: "GET", cache: "no-store" });
      if (r.ok) {
        const text = await r.text();
        if (text && text !== "null") {
          // Server may return the response either as direct JSON or as
          // a b64url(canonical_json) blob. Accept both.
          let raw: unknown;
          try { raw = JSON.parse(text); } catch {
            try { raw = JSON.parse(new TextDecoder().decode(b64UrlToBytes(text))); }
            catch { raw = null; }
          }
          const okParse = RpVerifyResponseSchema.safeParse(raw);
          const errParse = RpVerifyErrorResponseSchema.safeParse(raw);
          if (errParse.success && errParse.data.request_id === ctx.request.request_id) {
            dismiss();
            return { kind: "got_response", response: errParse.data };
          }
          if (okParse.success && okParse.data.request_id === ctx.request.request_id) {
            dismiss();
            return { kind: "got_response", response: okParse.data };
          }
        }
      }
    } catch {
      // Network blip; keep polling until deadline.
    }
    await new Promise((r) => setTimeout(r, interval));
  }

  dismiss();
  return { kind: "timeout" };
}

// ── Helpers (used by dispatcher & re-exported) ────────────────────────────

export { bytesToB64Url, b64UrlToBytes };
